// ============================================================
// Calculer les KPIs qualité hebdomadaires
// ============================================================
// KPIs calculés :
//   - note_moyenne_globale : moyenne des notes globales satisfaction
//   - taux_recommandation : % de recommandation (oui/total)
//   - nb_reclamations_ouvertes : réclamations non clôturées
//   - taux_completion_emargement : % émargements complétés
// ============================================================

const satisfactions = $input.all().map(item => item.json);

// Note moyenne globale
const notes = satisfactions
  .map(s => parseFloat(s.note_globale || s.note_moyenne || 0))
  .filter(n => !isNaN(n) && n > 0);
const noteMoyenne = notes.length > 0
  ? (notes.reduce((sum, n) => sum + n, 0) / notes.length).toFixed(2)
  : '0';

// Taux de recommandation
const recommandations = satisfactions.filter(s =>
  s.recommandation === 'TRUE' || s.recommandation === true || s.recommandation === 'oui'
);
const tauxRecommandation = satisfactions.length > 0
  ? ((recommandations.length / satisfactions.length) * 100).toFixed(1)
  : '0';

// Nombre de réclamations ouvertes (depuis le node Lire Réclamations)
// On compte les réclamations qui ne sont pas clôturées
let nbReclamationsOuvertes = 0;
try {
  const reclamations = $('Lire Réclamations').all().map(item => item.json);
  nbReclamationsOuvertes = reclamations.filter(r =>
    r.statut !== 'cloturee' && r.statut !== 'resolue'
  ).length;
} catch (e) {
  nbReclamationsOuvertes = 0;
}

// Taux de complétion émargement
const totalInscrits = satisfactions.length || 1;
const emargementComplets = satisfactions.filter(s =>
  s.emargement_ok === 'TRUE' || s.emargement_ok === true
).length;
const tauxEmargement = ((emargementComplets / totalInscrits) * 100).toFixed(1);

const dateCalcul = new Date().toLocaleDateString('fr-FR');
const semaine = `S${Math.ceil((new Date().getTime() - new Date(new Date().getFullYear(), 0, 1).getTime()) / (7 * 24 * 60 * 60 * 1000))}`;

return [{
  json: {
    date: dateCalcul,
    semaine,
    note_moyenne_globale: noteMoyenne,
    taux_recommandation: tauxRecommandation,
    nb_reclamations_ouvertes: nbReclamationsOuvertes,
    taux_completion_emargement: tauxEmargement,
    nb_reponses_satisfaction: satisfactions.length
  }
}];
